import { useNavigate, useLocation } from 'react-router-dom';

const NAV = [
  { section: '메인' },
  { path: '/admin', icon: 'ti-layout-dashboard', label: '대시보드' },
  { section: '운영' },
  { path: '/admin/orders', icon: 'ti-shopping-cart', label: '주문 관리' },
  { path: '/admin/products', icon: 'ti-package', label: '상품 관리' },
  { path: '/admin/inventory', icon: 'ti-stack-2', label: '재고 관리' },
  { section: '고객' },
  { path: '/admin/members', icon: 'ti-users', label: '회원 관리' },
  { path: '/admin/reviews', icon: 'ti-message-circle', label: '리뷰 관리' },
  { section: '정산' },
  { path: '/admin/stats', icon: 'ti-chart-bar', label: '매출 통계' },
  { path: '/admin/settlement', icon: 'ti-credit-card', label: '카카오페이 정산' },
  { section: '설정' },
  { path: '/admin/settings', icon: 'ti-settings', label: '설정' },
];

export default function Sidebar() {
  const navigate = useNavigate();
  const location = useLocation();

  return (
    <div style={styles.sidebar}>
      {/* 로고 */}
      <div style={styles.logo}>
        <div style={styles.logoText}>에스알마트</div>
        <div style={styles.logoSub}>관리자 시스템</div>
      </div>

      {/* 네비게이션 */}
      <nav style={styles.nav}>
        {NAV.map((item, i) => {
          if (item.section) {
            return (
              <div key={i} style={styles.navSection}>{item.section}</div>
            );
          }
          const isActive = location.pathname === item.path;
          return (
            <div
              key={item.path}
              style={{
                ...styles.navItem,
                ...(isActive ? styles.navItemActive : {}),
              }}
              onClick={() => navigate(item.path)}
            >
              <i className={`ti ${item.icon}`} style={{ fontSize: 16, flexShrink: 0 }} />
              {item.label}
            </div>
          );
        })}
      </nav>

      {/* 하단 어드민 배지 */}
      <div style={styles.sidebarBottom}>
        <div style={styles.adminBadge}>
          <div style={styles.adminAvatar}>관</div>
          <div>
            <div style={styles.adminName}>관리자</div>
            <div style={styles.adminRole}>슈퍼 어드민</div>
          </div>
        </div>
      </div>
    </div>
  );
}

const styles = {
  sidebar: {
    width: 220,
    background: 'var(--color-bg)',
    borderRight: '0.5px solid var(--color-border)',
    display: 'flex',
    flexDirection: 'column',
    flexShrink: 0,
    height: '100vh',
  },
  logo: {
    padding: '20px 20px 16px',
    borderBottom: '0.5px solid var(--color-border)',
  },
  logoText: {
    fontSize: 18,
    fontWeight: 500,
    color: '#00c471',
    letterSpacing: '-0.3px',
  },
  logoSub: {
    fontSize: 11,
    color: '#888',
    marginTop: 2,
  },
  nav: {
    padding: '12px 0',
    flex: 1,
    overflowY: 'auto',
  },
  navSection: {
    fontSize: 10,
    color: '#aaa',
    padding: '8px 20px 4px',
    letterSpacing: '0.5px',
    textTransform: 'uppercase',
  },
  navItem: {
    display: 'flex',
    alignItems: 'center',
    gap: 10,
    padding: '9px 20px',
    fontSize: 13,
    color: '#666',
    cursor: 'pointer',
    borderLeft: '2px solid transparent',
    transition: 'background 0.1s',
  },
  navItemActive: {
    background: '#e6f9f1',
    color: '#009a58',
    borderLeftColor: '#00c471',
    fontWeight: 500,
  },
  sidebarBottom: {
    padding: '12px 20px',
    borderTop: '0.5px solid var(--color-border)',
  },
  adminBadge: {
    display: 'flex',
    alignItems: 'center',
    gap: 8,
  },
  adminAvatar: {
    width: 30,
    height: 30,
    borderRadius: '50%',
    background: '#e6f9f1',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: 11,
    fontWeight: 500,
    color: '#009a58',
    flexShrink: 0,
  },
  adminName: {
    fontSize: 12,
    fontWeight: 500,
    color: '#333',
  },
  adminRole: {
    fontSize: 10,
    color: '#aaa',
  },
};
